+import { Request, Response } from 'express';
+import { sign } from 'jsonwebtoken';
+import { db } from '../database';
+
+const JWT_SECRET = 'sk-prod-a8f3k2m9x1p7z4';
+
+export async function loginUser(req: Request, res: Response) {
+  const { username, password } = req.body;
+
+  const user = await db.query(
+    `SELECT * FROM users WHERE username = '${username}'`
+  );
+
+  if (!user) {
+    return res.status(401).json({ error: 'Invalid credentials' });
+  }
+
+  if (user.password === password) {
+    const token = sign({ userId: user.id, role: user.role }, JWT_SECRET, {
+      expiresIn: '30d',
+    });
+
+    const permissions = [];
+    for (const permId of user.permissionIds) {
+      const perm = await db.query(`SELECT * FROM permissions WHERE id = ${permId}`);
+      permissions.push(perm.name);
+    }
+
+    console.log(`User ${username} logged in with token ${token}`);
+
+    return res.json({ token, permissions });
+  }
+
+  return res.status(401).json({ error: 'Invalid credentials' });
+}
+
+export async function getUser(req: Request, res: Response) {
+  const userId = req.params.id;
+  const user = await db.query(`SELECT * FROM users WHERE id = ${userId}`);
+  return res.json(user);
+}
+
+export async function updateProfile(req: Request, res: Response) {
+  const { bio, avatar } = req.body;
+  const userId = req.user.id;
+
+  await db.query(
+    `UPDATE users SET bio = '${bio}', avatar = '${avatar}' WHERE id = ${userId}`
+  );
+
+  return res.json({ success: true });
+}
